-- Generacion de datos tabla Libros_Electronicos
DELETE FROM [BibliotecaVirtual].[Libros_Electronicos]

DECLARE @Contador INT = 1
DECLARE @MaxISBN INT = 135

WHILE @Contador <= @MaxISBN
BEGIN
    VALUES (@Contador, 'http://ejemplo.com/libro_' + CAST(@Contador AS VARCHAR), 'PDF', 1000)

    SET @Contador = @Contador + 1
END
